import React, {Component} from 'react'
import Select from 'react-select'
import {connect} from 'react-redux'
import {changeSelection} from '../../actions'
import {articlesSelector} from '../../selectors'

class SelectFilter extends Component {
    render() {
        return (
            <Select
                options={this.options}
                value={this.props.selectedOptions}
                onChange={this.handleSelectChange}
                isMulti
            />
        )
    }

    handleSelectChange = (selectedOption) => {
        this.props.changeSelection(selectedOption)
    }

    get options() {
        return this.props.articles.map(article => ({
            value: article.id,
            label: article.title
        }))
    }
}

/*
const mapDispatchToPropsFunc = dispatch => {
    return {
        changeSelection: (selectedOption) => {
            dispatch(changeSelection(selectedOption))
        }
    }
}

const mapDispatchToProps = {
    changeSelection: changeSelection
}
*/

export default connect(
    state => ({
        articles: articlesSelector(state),
        selectedOptions: filtersSelector(state).selected
    }),
    {changeSelection}
)(SelectFilter)
